from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    username = db.Column(db.String(64), unique=True, nullable=False)
    role = db.Column(db.String(10), nullable=False, default='user')
    account_status = db.Column(db.String(10), nullable=False, default='active')
    subscription_tier = db.Column(db.String(10), nullable=False, default='free')

class CurrentUser:
    def __init__(self, user):
        self.user = user

@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    current_user = CurrentUser(User.query.get(current_user.id))
    
    if request.json['email']:
        User.query.filter_by(id=user_id).update({'email': request.json['email']})
        
    if request.json['username']:
        User.query.filter_by(id=user_id).update({'username': request.json['username']})
        
    if 'role' in request.json and current_user.user.role == 'admin':
        User.query.filter_by(id=user_id).update({'role': request.json['role']})
        
    if 'account_status' in request.json and current_user.user.role == 'admin':
        User.query.filter_by(id=user_id).update({'account_status': request.json['account_status']})
        
    if 'subscription_tier' in request.json and current_user.user.role == 'admin':
        User.query.filter_by(id=user_id).update({'subscription_tier': request.json['subscription_tier']})
        
    db.session.commit()
    
    return jsonify({'message': 'User updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)